body.script:
promise_test(async () => {
  const t1 = document.getElementById('t1');
  let actions = new test_driver.Actions();
  await actions.pointerMove(0, 0, {origin: t1})
               .pointerDown()
               .send();
  assert_equals(getComputedStyle(t1).backgroundColor, 'rgb(0, 128, 0)', "button should be green when active");

  actions = new test_driver.Actions();
  await actions.pointerUp().send();
}, "active pseudo-class on button");
